(1, 'user_registration', 'Willkommen bei ScamRecovery - Ihr Konto wurde erstellt', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Willkommen bei ScamRecovery</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-color: #e8e5ef; border-radius: 2px; border-width: 1px; box-shadow: 0 2px 0 rgba(0, 0, 150, 0.025), 2px 4px 0 rgba(0, 0, 150, 0.015); margin: 0 auto; padding: 0; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>vielen Dank für Ihre Registrierung bei ScamRecovery. Ihr Konto wurde erfolgreich erstellt.</p>\r\n\r\n<p>Ihre Anmeldedaten:</p>\r\n\r\n<ul>\r\n\r\n<li>E-Mail: {email}</li>\r\n\r\n<li>Passwort: Das von Ihnen gewählte Passwort</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n<a href=\"{verification_link}\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; display: inline-block; padding: 10px 18px; color: #ffffff; background-color: #1a202c; border-radius: 3px; text-decoration: none;\">E-Mail bestätigen</a>\r\n\r\n</p>\r\n\r\n<p>Falls Sie sich nicht registriert haben, ignorieren Sie bitte diese E-Mail.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr ScamRecovery Team</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"footer\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; margin: 0 auto; padding: 0; text-align: center; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; line-height: 1.5em; margin-top: 0; color: #b0adc5; font-size: 12px; text-align: center;\">© 2025 ScamRecovery. Alle Rechte vorbehalten.</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</body>\r\n\r\n</html>', '[\"first_name\", \"last_name\", \"email\", \"verification_link\"]', '1', '2025-08-02 06:52:21', '2026-02-28 05:35:04'),
(2, 'case_created1', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Neuer Fall erstellt</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-color: #e8e5ef; border-radius: 2px; border-width: 1px; box-shadow: 0 2px 0 rgba(0, 0, 150, 0.025), 2px 4px 0 rgba(0, 0, 150, 0.015); margin: 0 auto; padding: 0; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>vielen Dank für die Einreichung Ihres Falls bei ScamRecovery. Wir haben Ihren Fall erhalten und werden uns so schnell wie möglich bei Ihnen melden.</p>\r\n\r\n<div style=\"background-color: #fff; border: 1px solid #ddd; padding: 15px; margin: 15px 0; border-radius: 5px;\">\r\n\r\n<h3>Falldetails:</h3>\r\n\r\n<p><strong>Fallnummer:</strong> {case_number}</p>\r\n\r\n<p><strong>Plattform:</strong> {platform_name}</p>\r\n\r\n<p><strong>Gemeldeter Betrag:</strong> {reported_amount} €</p>\r\n\r\n<p><strong>Beschreibung:</strong> {case_description}</p>\r\n\r\n<p><strong>Status:</strong> {case_status}</p>\r\n\r\n</div>\r\n\r\n<p>Bitte stellen Sie alle relevanten Dokumente über Ihr Kundenportal bereit, um den Prozess zu beschleunigen.</p>\r\n\r\n<p>Sie können den Fortschritt Ihres Falls jederzeit in Ihrem Konto einsehen.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr ScamRecovery Team</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"footer\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; margin: 0 auto; padding: 0; text-align: center; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; line-height: 1.5em; margin-top: 0; color: #b0adc5; font-size: 12px; text-align: center;\">© 2025 ScamRecovery. Alle Rechte vorbehalten.</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</body>\r\n\r\n</html>', '[\"first_name\", \"last_name\", \"case_number\", \"platform_name\", \"reported_amount\", \"case_description\", \"case_status\"]', '1', '2025-08-02 06:52:21', '2026-02-28 05:35:04'),
(3, 'case_status_updated', 'Fallstatus aktualisiert - Fallnummer: {case_number}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Fallstatus aktualisiert – TradeVest Crypto</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n    .highlight-box h3 {\r\n      margin-top: 0;\r\n      color: #007bff;\r\n    }\r\n    .highlight-box p {\r\n      margin: 6px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 10px 18px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin-top: 15px;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Fallstatus aktualisiert – {case_number}</h1>\r\n      <p>Aktuelle Informationen zu Ihrem Fall</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Der Status Ihres Falls wurde erfolgreich aktualisiert.  \r\n        Nachfolgend finden Sie die neuesten Informationen:\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>📄 Aktualisierte Falldetails</h3>\r\n        <p><strong>Fallnummer:</strong> {case_number}</p>\r\n        <p><strong>Vorheriger Status:</strong> {old_status}</p>\r\n        <p><strong>Neuer Status:</strong> {new_status}</p>\r\n        <p><strong>Grund / Notizen:</strong> {status_notes}</p>\r\n        <p><strong>Datum der Änderung:</strong> {update_date}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können den aktuellen Stand Ihres Falls jederzeit in Ihrem\r\n        <strong>Kundenportal</strong> einsehen und relevante Unterlagen hochladen.\r\n      </p>\r\n\r\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n     <div class=\"signature\">\r\n    <img src=\"{site_url}/assets/images/logo/logo.png\" alt=\"{brand_name} Logo\"><br>\r\n    <strong>{brand_name} – Fallmanagement-Team</strong><br>\r\n    {company_address}<br>\r\n    E: <a href=\"mailto:{contact_email}\">{contact_email}</a> | \r\n    W: <a href=\"{site_url}\">{brand_name}</a>\r\n    <p>\r\n      BaFin Referenc Nr: {fca_reference_number}<br>\r\n      <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n      Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n    </p>\r\n</div>\r\n\r\n<div class=\"footer\">\r\n    © {current_year} {brand_name}. Alle Rechte vorbehalten.\r\n</div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"case_number\", \"old_status\", \"new_status\",\"site_url\", \"status_notes\", \"update_date\",\"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n]', '1', '2025-08-02 06:52:21', '2026-02-28 05:35:04'),
(4, 'documents_required', 'Dokumente erforderlich für Fallnummer: {case_number}', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Appl