px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Einzahlung erhalten</h1>\r\n      <p>Ihre Transaktion wurde erfolgreich verbucht</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir bestätigen den erfolgreichen Eingang Ihrer <strong>Einzahlung</strong>.  \r\n        Der Betrag wurde Ihrem Kontoguthaben gutgeschrieben und steht Ihnen ab sofort zur Verfügung.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> {transaction_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können Ihre vollständige Transaktionshistorie sowie Ihr aktuelles Guthaben  \r\n        jederzeit in Ihrem <strong>Kundenportal