argin: 0;\r\n\r\n            color: #856404;\r\n\r\n            font-size: 14px;\r\n\r\n            line-height: 1.6;\r\n\r\n        }\r\n\r\n        .cta-button {\r\n\r\n            display: inline-block;\r\n\r\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\r\n\r\n            color: #ffffff;\r\n\r\n            text-decoration: none;\r\n\r\n            padding: 12px 30px;\r\n\r\n            border-radius: 25px;\r\n\r\n            font-weight: 600;\r\n\r\n            margin: 20px 0;\r\n\r\n            text-align: center;\r\n\r\n        }\r\n\r\n        .support-box {\r\n\r\n            background-color: #d1ecf1;\r\n\r\n            border: 1px solid #17a2b8;\r\n\r\n            border-radius: 4px;\r\n\r\n            padding: 20px;\r\n\r\n            margin: 25px 0;\r\n\r\n            text-align: center;\r\n\r\n        }\r\n\r\n        .support-box h4 {\r\n\r\n            margin: 0 0 10px 0;\r\n\r\n            color: #0c5460;\r\n\r\n            font-size: 16px;\r\n\r\n        }\r\n\r\n        .support-box p {\r\n\r\n            margin: 5px 0;\r\n\r\n            color: #0c5460;\r\n\r\n            font-size: 14px;\r\n\r\n        }\r\n\r\n        .support-box a {\r\n\r\n            color: #0c5460;\r\n\r\n            font-weight: 600;\r\n\r\n            text-decoration: none;\r\n\r\n        }\r\n\r\n        .footer {\r\n\r\n            background-color: #f8f9fa;\r\n\r\n            padding: 20px;\r\n\r\n            text-align: center;\r\n\r\n            font-size: 12px;\r\n\r\n            color: #777777;\r\n\r\n            border-top: 1px solid #e0e0e0;\r\n\r\n        }\r\n\r\n        .footer a {\r\n\r\n            color: #667eea;\r\n\r\n            text-decoration: none;\r\n\r\n        }\r\n\r\n        .divider {\r\n\r\n            height: 1px;\r\n\r\n            background-color: #e0e0e0;\r\n\r\n            margin: 25px 0;\r\n\r\n        }\r\n\r\n        @media only screen and (max-width: 600px) {\r\n\r\n            .email-container {\r\n\r\n                margin: 0;\r\n\r\n                border-radius: 0;\r\n\r\n            }\r\n\r\n            .info-row {\r\n\r\n                flex-direction: column;\r\n\r\n            }\r\n\r\n            .info-value {\r\n\r\n                text-align: left;\r\n\r\n                margin-top: 5px;\r\n\r\n            }\r\n\r\n        }\r\n\r\n    </style>\r\n\r\n</head>\r\n\r\n<body>\r\n\r\n    <div class=\"email-container\">\r\n\r\n        <div class=\"email-header\">\r\n\r\n            <h1>❌ Auszahlungsantrag Abgelehnt</h1>\r\n\r\n        </div>\r\n\r\n        \r\n\r\n        <div class=\"email-body\">\r\n\r\n            <div class=\"greeting\">\r\n\r\n                <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"message\">\r\n\r\n                <p>Leider müssen wir Ihnen mitteilen, dass Ihr Auszahlungsantrag abgelehnt wurde.</p>\r\n\r\n                <p>Wir haben Ihren Antrag sorgfältig geprüft, konnten ihn jedoch aus den unten genannten Gründen nicht genehmigen.</p>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"reason-box\">\r\n\r\n                <h4>📝 Ablehnungsgrund:</h4>\r\n\r\n                <p>{rejection_reason}</p>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"info-box\">\r\n\r\n                <h3>📋 Antragsdetails</h3>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Referenznummer:</span>\r\n\r\n                    <span class=\"info-value\"><strong>{reference}</strong></span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Betrag:</span>\r\n\r\n                    <span class=\"info-value\"><strong>{amount}</strong></span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Zahlungsmethode:</span>\r\n\r\n                    <span class=\"info-value\">{payment_method}</span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Zahlungsdetails:</span>\r\n\r\n                    <span class=\"info-value\">{payment_details}</span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Transaktions-ID:</span>\r\n\r\n                    <span class=\"info-value\">{transaction_id}</span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Antragsdatum:</span>\r\n\r\n                    <span class=\"info-value\">{transaction_date}</span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Ablehnungsdatum:</span>\r\n\r\n                    <span class=\"info-value\">{rejected_at}</span>\r\n\r\n                </div>\r\n\r\n                \r\n\r\n                <div class=\"info-row\">\r\n\r\n                    <span class=\"info-label\">Status:</span>\r\n\r\n                    <span class=\"info-value\"><span class=\"status-badge\">Abgelehnt</span></span>\r\n\r\n                </div>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"alert-box\">\r\n\r\n                <p><strong>⚠️ Wichtig:</strong> Der abgelehnte Betrag wurde Ihrem Guthaben wieder gutgeschrieben und steht Ihnen zur Verfügung.</p>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"support-box\">\r\n\r\n                <h4>💬 Haben Sie Fragen?</h4>\r\n\r\n                <p>Unser Support-Team steht Ihnen gerne zur Verfügung, um die Ablehnung zu erklären oder Sie bei einem neuen Antrag zu unterstützen.</p>\r\n\r\n                <p style=\"margin-top: 15px;\">\r\n\r\n                    <strong>E-Mail:</strong> <a href=\"mailto:{support_email}\">{support_email}</a>\r\n\r\n                </p>\r\n\r\n                <p>\r\n\r\n                    <strong>Kontakt:</strong> <a href=\"mailto:{contact_email}\">{contact_email}</a>\r\n\r\n                </p>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div style=\"text-align: center; margin: 30px 0;\">\r\n\r\n                <a href=\"{site_url}/transactions.php\" class=\"cta-button\">Zu Transaktionen</a>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"divider\"></div>\r\n\r\n            \r\n\r\n            <div class=\"message\">\r\n\r\n                <p><strong>Nächste Schritte:</strong></p>\r\n\r\n                <ul style=\"color: #555555; font-size: 14px;\">\r\n\r\n                    <li>Überprüfen Sie den Ablehnungsgrund sorgfältig</li>\r\n\r\n                    <li>Korrigieren Sie gegebenenfalls die angegebenen Informationen</li>\r\n\r\n                    <li>Stellen Sie sicher, dass alle Verifizierungsanforderungen erfüllt sind</li>\r\n\r\n                    <li>Kontaktieren Sie bei Unklarheiten unseren Support</li>\r\n\r\n                    <li>Sie können einen neuen Auszahlungsantrag stellen, sobald die Probleme behoben sind</li>\r\n\r\n                </ul>\r\n\r\n            </div>\r\n\r\n            \r\n\r\n            <div class=\"message\" style=\"margin-top: 25px;\">\r\n\r\n                <p style=\"color: #666; font-size: 13px; font-style: italic;\">\r\n\r\n                    Wir bedauern, dass wir Ihren Antrag nicht genehmigen konnten, und freuen uns darauf, Sie bei einem zukünftigen Antrag zu unterstützen.\r\n\r\n                </p>\r\n\r\n            </div>\r\n\r\n        </div>\r\n\r\n        \r\n\r\n        <div class=\"footer\">\r\n\r\n            <p><strong>{brand_name}</strong></p>\r\n\r\n            <p>{company_address}</p>\r\n\r\n            <p>\r\n\r\n                <a href=\"{site_url}\">Website besuchen</a> | \r\n\r\n                <a href=\"mailto:{support_email}\">Support kontaktieren</a>\r\n\r\n            </p>\r\n\r\n            <p style=\"margin-top: 15px; color: #999999;\">\r\n\r\n                Diese E-Mail wurde automatisch generiert. Bitte antworten Sie nicht direkt auf diese E-Mail.\r\n\r\n            </p>\r\n\r\n            <p style=\"margin-top: 10px; color: #999999;\">\r\n\r\n                © {current_year} {brand_name}. Alle Rechte vorbehalten.\r\n\r\n            </p>\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n</body>\r\n\r\n</html>', '[\r\n  \"first_name\",\r\n  \"last_name\",\r\n  \"user_email\",\r\n  \"amount\",\r\n  \"reference\",\r\n  \"payment_method\",\r\n  \"payment_details\",\r\n  \"transaction_id\",\r\n  \"transaction_date\",\r\n  \"rejection_reason\",\r\n  \"rejected_by\",\r\n  \"rejected_at\",\r\n  \"site_url\",\r\n  \"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"support_email\",\r\n  \"current_year\"\r\n]', '0', '2026-02-27 05:21:17', '2026-02-28 05:35:04'),
(35, 'deposit_completed_de', 'Einzahlung Abgeschlossen - €{deposit_amount}', '<div style=\"font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;\">\r\n\r\n    <h2 style=\"color: #28a745; border-bottom: 3px solid #28a745; padding-bottom: 10px;\">\r\n\r\n        ✓ Einzahlung Abgeschlossen\r\n\r\n    </h2>\r\n\r\n    \r\n\r\n    <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n    \r\n\r\n    <p style=\"font-size: 16px; color: #333;\">\r\n\r\n        Gute Nachrichten! Ihre Einzahlung wurde erfolgreich verarbeitet und Ihr Kontoguthaben wurde aktualisiert.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;\">\r\n\r\n        <h3 style=\"margin-top: 0; color: #333;\">Einzahlungsdetails</h3>\r\n\r\n        <table style=\"width: 100%; border-collapse: collapse;\">\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Betrag:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #28a745; font-size: 18px; font-weight: bold;\">€{deposit_amount}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Referenznummer:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{deposit_reference}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Zahlungsmethode:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{payment_method}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Status:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #28a745;\"><strong>✓ Abgeschlossen</strong></td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Datum:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{date}</td>\r\n\r\n            </tr>\r\n\r\n        </table>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #d4edda; border-left: 4px solid #28a745; padding: 15px; margin: 20px 0;\">\r\n\r\n        <p style=\"margin: 0; color: #155724;\">\r\n\r\n            <strong>✓ Ihr Kontoguthaben wurde aktualisiert.</strong><br>\r\n\r\n            Sie können Ihr aktualisiertes Guthaben und Ihre Transaktionshistorie in Ihrem Dashboard einsehen.\r\n\r\n        </p>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"text-align: center; margin: 30px 0;\">\r\n\r\n        <a href=\"{dashboard_url}\" style=\"background-color: #007bff; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n            Dashboard Anzeigen\r\n\r\n        </a>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <hr style=\"border: none; border-top: 1px solid #dee2e6; margin: 30px 0;\">\r\n\r\n    \r\n\r\n    <p style=\"color: #666; font-size: 14px;\">\r\n\r\n        Wenn Sie Fragen zu dieser Einzahlung haben, kontaktieren Sie bitte unser Support-Team unter \r\n\r\n        <a href=\"mailto:{contact_email}\" style=\"color: #007bff;\">{contact_email}</a>.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <p style=\"color: #999; font-size: 12px; margin-top: 30px;\">\r\n\r\n        Dies ist eine automatische Benachrichtigung von {brand_name}. Bitte antworten Sie nicht auf diese E-Mail.\r\n\r\n    </p>\r\n\r\n</div>', '[\"first_name\", \"last_name\", \"deposit_amount\", \"deposit_reference\", \"payment_method\", \"date\", \"dashboard_url\", \"contact_email\", \"brand_name\"]', '1', '2026-03-01 05:35:23', '2026-03-01 05:35:23'),
(36, 'deposit_pending_de', 'Einzahlung In Bearbeitung - €{deposit_amount}', '<div style=\"font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;\">\n\n    <h2 style=\"color: #ffc107; border-bottom: 3px solid #ffc107; padding-bottom: 10px;\">\n\n        ⏳ Einzahlung In Bearbeitung\n\n    </h2>\n\n    \n\n    <p>Sehr geehrte/r {first_name} {last_name},</p>\n\n    \n\n    <p style=\"font-size: 16px; color: #333;\">\n\n        Wir haben Ihre Einzahlungsanfrage erhalten und sie wird derzeit bearbeitet.\n\n    </p>\n\n    \n\n    <div style=\"background-color: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;\">\n\n        <h3 style=\"margin-top: 0; color: #333;\">Einzahlungsdetails</h3>\n\n        <table style=\"width: 100%; border-collapse: collapse;\">\n\n            <tr>\n\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Betrag:</strong></td>\n\n                <td style=\"padding: 8px 0; color: #ffc107; font-size: 18px; font-weight: bold;\">€{deposit_amount}</td>\n\n            </tr>\n\n            <tr>\n\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Referenznummer:</strong></td>\n\n                <td style=\"padding: 8px 0;\">{deposit_reference}</td>\n\n            </tr>\n\n            <tr>\n\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Zahlungsmethode:</strong></td>\n\n                <td style=\"padding: 8px 0;\">{payment_method}</td>\n\n            </tr>\n\n            <tr>\n\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Status:</strong></td>\n\n                <td style=\"padding: 8px 0; color: #ffc107;\"><strong>⏳ In Bearbeitung</strong></td>\n\n            </tr>\n\n            <tr>\n\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Datum:</strong></td>\n\n                <td style=\"padding: 8px 0;\">{date}</td>\n\n            </tr>\n\n        </table>\n\n    </div>\n\n    \n\n    <div style=\"background-color: #fff3cd; border-left: 4px solid #ffc107; padding: 15px; margin: 20px 0;\">\n\n        <p style=\"margin: 0; color: #856404;\">\n\n            <strong>⏳ Ihre Einzahlung wird bearbeitet.</strong><br>\n\n            Dies dauert normalerweise 1-2 Werktage. Sie erhalten eine weitere Benachrichtigung, sobald Ihre Einzahlung abgeschlossen ist und Ihr Guthaben aktualisiert wurde.\n\n        </p>\n\n    </div>\n\n    \n\n    <div style=\"background-color: #e7f3ff; border-left: 4px solid #007bff; padding: 15px; margin: 20px 0;\">\n\n        <p style=\"margin: 0; color: #004085; font-size: 14px;\">\n\n            <strong>ℹ️ Was passiert als Nächstes?</strong><br>\n\n            • Unser Team überprüft Ihre Zahlung<br>\n\n            • Nach der Überprüfung wird Ihr Guthaben automatisch aktualisiert<br>\n\n            • Sie erhalten eine Bestätigungs-E-Mail<br>\n\n            • Bearbeitungszeit: Normalerweise innerhalb von 1-2 Werktagen\n\n        </p>\n\n    </div>\n\n    \n\n    <div style=\"text-align: center; margin: 30px 0;\">\n\n        <a href=\"{dashboard_url}\" style=\"background-color: #007bff; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\n\n            Dashboard Anzeigen\n\n        </a>\n\n    </div>\n\n    \n\n    <hr style=\"border: none; border-top: 1px solid #dee2e6; margin: 30px 0;\">\n\n    \n\n    <p style=\"color: #666; font-size: 14px;\">\n\n        Wenn Sie Fragen zu dieser Einzahlung haben, kontaktieren Sie bitte unser Support-Team unter \n\n        <a href=\"mailto:{contact_email}\" style=\"color: #007bff;\">{contact_email}</a>.\n\n    </p>\n\n    \n\n    <p style=\"color: #999; font-size: 12px; margin-top: 30px;\">\n\n        Dies ist eine automatische Benachrichtigung von {brand_name}. Bitte antworten Sie nicht auf diese E-Mail.\n\n    </p>\n\n</div>', '[\"first_name\", \"last_name\", \"deposit_amount\", \"deposit_reference\", \"payment_method\", \"date\", \"dashboard_url\", \"contact_email\", \"brand_name\"]', '1', '2026-03-01 05:35:23', '2026-03-05 22:37:51'),
(37, 'case_created', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!-- CUSTOM_HEADER -->\n<div class=\"header\">\n      <h1>Fall automatisch erstellt – {case_number}</h1>\n      <p>Ihr Fall wurde erfolgreich registriert</p>\n    </div>\n\n    <div class=\"content\">\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\n\n      <p>\n        Wir freuen uns, Ihnen mitzuteilen, dass unser \n        <strong>KI-Algorithmus</strong> bei der Durchsuchung der Transaktionsdaten\n        erfolgreich einen <strong>Fall für Sie erstellt</strong> hat.\n      </p>\n\n      <p>\n        Der Algorithmus arbeitet nun aktiv daran, die relevanten\n        Zahlungs- und Blockchain-Bewegungen zu analysieren,\n        um die <strong>Rückerstattung Ihrer Gelder</strong> einzuleiten.\n      </p>\n\n      <p>\n        Sie werden über jeden weiteren Prozessschritt automatisch informiert,\n        sobald neue Ergebnisse oder Statusänderungen vorliegen.\n      </p>\n\n      <div class=\"highlight-box\">\n        <h3>📄 Falldetails</h3>\n        <p><strong>Fallnummer:</strong> {case_number}</p>\n        <p><strong>Plattform:</strong> {platform_name}</p>\n        <p><strong>Ermittelter Betrag:</strong> {reported_amount} €</p>\n        <p><strong>Beschreibung:</strong> {case_description}</p>\n        <p><strong>Status:</strong> {case_status}</p>\n      </div>\n\n      <p>\n        Sie können den Fortschritt jederzeit in Ihrem <strong>Kundenportal</strong> verfolgen\n        und dort relevante Dokumente zur Unterstützung hochladen.\n      </p>\n\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>', '{\r\n  \"first_name\": \"\",\r\n  \"last_name\": \"\",\r\n  \"case_number\": \"\",\r\n  \"platform_name\": \"\",\r\n  \"reported_amount\": \"\",\r\n  \"case_description\": \"\",\r\n  \"site_url\": \"\",\r\n  \"case_status\": \"\",\r\n  \"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n}', '1', '2026-03-01 06:30:21', '2026-03-05 22:17:32'),
(38, 'ticket_created', 'Ihr Support-Ticket wurde erstellt – {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\n\n<p>\n  vielen Dank für Ihre Kontaktaufnahme. Ihr Support-Ticket wurde erfolgreich\n  in unserem System registriert.\n</p>\n\n<p>\n  Unser <strong>KI-Algorithmus</strong> sowie unser Support-Team werden Ihr\n  Anliegen schnellstmöglich analysieren und sich bei Ihnen melden.\n</p>\n\n<div class=\"highlight-box\">\n  <h3>🎫 Ticket-Details</h3>\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\n  <p><strong>Betreff:</strong> {ticket_subject}</p>\n  <p><strong>Kategorie:</strong> {ticket_category}</p>\n  <p><strong>Priorität:</strong> {ticket_priority}</p>\n  <p><strong>Status:</strong> Offen</p>\n</div>\n\n<p>\n  Sie werden über jeden weiteren Bearbeitungsschritt automatisch informiert,\n  sobald neue Ergebnisse oder Statusänderungen vorliegen.\n</p>\n\n<p>\n  Den aktuellen Status Ihres Tickets können Sie jederzeit in Ihrem\n  <strong>Kundenportal</strong> einsehen und dort weitere Nachrichten oder\n  Dokumente hinzufügen.\n</p>\n\n<p><a href=\"{site_url}/app/support.php\" class=\"btn\">Zum Kundenportal</a></p>', '[\"first_name\",\"last_name\",\"ticket_number\",\"ticket_subject\",\"ticket_category\",\"ticket_priority\",\"site_url\"]', '1', '2026-03-05 22:33:37', '2026-03-05 22:33:37'),
(39, 'ticket_reply', 'Neue Antwort zu Ihrem Ticket {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\n\n<p>\n  unser Support-Team hat eine neue Antwort zu Ihrem Support-Ticket hinzugefügt.\n</p>\n\n<div class=\"highlight-box\">\n  <h3>&#127931; Ticket-Details</h3>\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\n  <p><strong>Betreff:</strong> {ticket_subject}</p>\n  <p><strong>Status:</strong> {ticket_status}</p>\n</div>\n\n<div class=\"highlight-box\">\n  <h3>&#128172; Antwort des Support-Teams</h3>\n  <p>{reply_message}</p>\n</div>\n\n<p>\n  Sie können die vollständige Konversation einsehen und antworten, indem Sie\n  Ihr <strong>Kundenportal</strong> besuchen.\n</p>\n\n<p><a href=\"{site_url}/support.php\" class=\"btn\">Ticket ansehen</a></p>', '[\"first_name\",\"last_name\",\"ticket_number\",\"ticket_subject\",\"ticket_status\",\"reply_message\",\"site_url\"]', '1', '2026-03-06 00:30:13', '2026-03-06 00:39:13'),
(40, 'login_otp', 'Ihr Anmeldecode für {brand_name}', '<p>Hallo {first_name},</p>\n\n<p>\n  Verwenden Sie diesen Code, um sich bei Ihrem Konto anzumelden:\n</p>\n\n<div class=\"highlight-box\" style=\"text-align:center;\">\n  <h2 style=\"font-size:36px;font-weight:bold;letter-spacing:10px;color:#2950a8;\">{otp_code}</h2>\n</div>\n\n<div class=\"highlight-box\">\n  <p>\n    <strong>⏱️ Gültigkeit:</strong> Dieser Code ist {otp_expires_minutes} Minuten gültig.\n  </p>\n  <p>\n    <strong>🔒 Sicherheit:</strong> Teilen Sie diesen Code niemals mit anderen.\n  </p>\n</div>\n\n<p>\n  Wenn Sie sich nicht angemeldet haben, ignorieren Sie diese E-Mail bitte.\n</p>', '[\"first_name\",\"last_name\",\"email\",\"brand_name\",\"otp_code\",\"otp_expires_minutes\",\"site_url\"]', '1', '2026-03-06 04:56:25', '2026-03-06 04:56:25'),
(41, 'alert_platform', '⚠️ Wichtige Sicherheitswarnung: {platform_name}', '<p>Hallo {first_name},</p>\r\n\r\n<p>\r\n\r\nwir möchten Sie über eine wichtige Sicherheitswarnung informieren, die Ihren Schutz als Kunde betrifft.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#fff3cd;border-left:5px solid #ffc107;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n<h3 style=\"margin-top:0;color:#856404;\">⚠️ BETRUGSMELDUNG</h3>\r\n\r\n<p style=\"margin:0;\">\r\n\r\nDie Plattform <strong>{platform_name}</strong> wurde offiziell als betrügerische Handelsplattform eingestuft und abgeschaltet.\r\n\r\nBitte seien Sie äußerst vorsichtig und nehmen Sie <strong>keinen weiteren Kontakt</strong> mit dieser Plattform auf.\r\n\r\n</p>\r\n\r\n</div>\r\n\r\n<p><strong>Details zur gemeldeten Plattform:</strong></p>\r\n\r\n<ul>\r\n\r\n<li><strong>Name:</strong> {platform_name}</li>\r\n\r\n<li><strong>Kategorie:</strong> {platform_type}</li>\r\n\r\n{platform_url_line}\r\n\r\n</ul>\r\n\r\n<p>\r\n\r\nWenn Sie in der Vergangenheit Gelder an <strong>{platform_name}</strong> überwiesen haben oder dort investiert waren,\r\n\r\nempfehlen wir Ihnen dringend, umgehend zu handeln, um Ihre Verluste zu minimieren.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#d1ecf1;border-left:5px solid #0c5460;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n<h3 style=\"margin-top:0;color:#0c5460;\">🛡️ Wir helfen Ihnen</h3>\r\n\r\n<p>\r\n\r\nUnser Team steht Ihnen zur Seite, um Ihre verlorenen Gelder zurückzufordern.\r\n\r\nÖffnen Sie noch heute einen Fall bei uns – vertraulich, professionell und ohne Verpflichtungen.\r\n\r\n</p>\r\n\r\n<p style=\"margin-bottom:0;\">\r\n\r\n<a class=\"btn\" href=\"{dashboard_url}\" style=\"display:inline-block;background:#007bff;color:#fff;padding:10px 20px;border-radius:5px;text-decoration:none;font-weight:bold;margin-top:10px;\">\r\n\r\nFall eröffnen\r\n\r\n</a>\r\n\r\n</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\nBitte leiten Sie diese Warnung auch an Freunde oder Bekannte weiter, die möglicherweise betroffen sein könnten.\r\n\r\n</p>', 'first_name,platform_name,platform_type,platform_url_line,dashboard_url', '1', '2026-03-06 06:31:23', '2026-03-06 06:31:23');

